INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'aba56820-e6fe-4950-ac95-2576ca5f7423',
  '00000000-0000-0000-0000-000000000001',
  $escape$oauth2 - Hashing vs Encryption: When to Hash Passwords, When to Encrypt Reversible Data$escape$,
  $escape$When using oauth2, it's essential to differentiate between hashing and encryption. Passwords are hashed using the `client_secret` parameter in the `authorization_code` flow to prevent unauthorized access. However, reversible data like refresh tokens are encrypted using the `refresh_token` endpoint. Hashing uses one-way functions like PBKDF2, while encryption uses symmetric keys like AES. Choose the right approach to secure your oauth2 implementation.$escape$,
  NULL,
  NULL,
